using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithSeedData(string? dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructor1 = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2010, 1, 15),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };

            var instructor2 = new Instructor
            {
                ID = 2,
                LastName = "Jones",
                FirstMidName = "Jane",
                HireDate = new DateTime(2012, 6, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            context.Instructors.AddRange(instructor1, instructor2);

            var department1 = new Department
            {
                DepartmentID = 1,
                Name = "Computer Science",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 1
            };

            var department2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 200000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 2
            };

            context.Departments.AddRange(department1, department2);

            var course1 = new Course
            {
                CourseID = 1001,
                Title = "Introduction to CS",
                Credits = 3,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            var course2 = new Course
            {
                CourseID = 1002,
                Title = "Calculus I",
                Credits = 4,
                DepartmentID = 2,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            var course3 = new Course
            {
                CourseID = 1003,
                Title = "Data Structures",
                Credits = 3,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            context.Courses.AddRange(course1, course2, course3);

            var student1 = new Student
            {
                ID = 10,
                LastName = "Anderson",
                FirstMidName = "Alice",
                EnrollmentDate = new DateTime(2020, 9, 1),
                Enrollments = new List<Enrollment>()
            };

            var student2 = new Student
            {
                ID = 11,
                LastName = "Brown",
                FirstMidName = "Bob",
                EnrollmentDate = new DateTime(2021, 1, 15),
                Enrollments = new List<Enrollment>()
            };

            var student3 = new Student
            {
                ID = 12,
                LastName = "Clark",
                FirstMidName = "Charlie",
                EnrollmentDate = new DateTime(2020, 9, 1),
                Enrollments = new List<Enrollment>()
            };

            context.Students.AddRange(student1, student2, student3);

            context.Enrollments.AddRange(
                new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 10, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 1002, StudentID = 10, Grade = Grade.B },
                new Enrollment { EnrollmentID = 3, CourseID = 1001, StudentID = 11, Grade = Grade.C }
            );

            var ca1 = new CourseAssignment { InstructorID = 1, CourseID = 1001 };
            var ca2 = new CourseAssignment { InstructorID = 1, CourseID = 1003 };
            var ca3 = new CourseAssignment { InstructorID = 2, CourseID = 1002 };
            context.CourseAssignments.AddRange(ca1, ca2, ca3);

            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Anderson", model[0].LastName);
            Assert.Equal("Brown", model[1].LastName);
            Assert.Equal("Clark", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Clark", model[0].LastName);
            Assert.Equal("Brown", model[1].LastName);
            Assert.Equal("Anderson", model[2].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            // Anderson and Clark both 2020-09-01, Brown 2021-01-15
            Assert.Equal(new DateTime(2021, 1, 15), model.Last().EnrollmentDate);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Brown", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Brown", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
            Assert.Equal("Brown", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alice", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
            Assert.Equal("Anderson", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_ResetsPageTo1()
        {
            var result = _controller.Index(null, null, "A", 5) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Brown", null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_WithNameDescSort_SetsNameSortParmToEmpty()
        {
            _controller.Index("name_desc", null, null, null);

            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_WithDateSort_SetsDateSortParmToDateDesc()
        {
            _controller.Index("Date", null, null, null);

            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_WithValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result!.Model);
            Assert.Equal("Anderson", student.LastName);
            Assert.NotNull(student.Enrollments);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_GET_ReturnsViewWithStudentHavingTodayDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result!.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "Doe",
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
        }

        [Fact]
        public void Create_POST_ValidStudent_AddsToDatabase()
        {
            var student = new Student
            {
                LastName = "Doe",
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.Equal(4, _context.Students.Count());
            Assert.Contains(_context.Students, s => s.LastName == "Doe");
        }

        [Fact]
        public void Create_POST_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Doe",
                FirstMidName = "John",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result!.Model);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_GET_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_WithValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(10) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result!.Model);
            Assert.Equal("Anderson", student.LastName);
        }

        [Fact]
        public void Edit_GET_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_POST_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.Find(10)!;
            student.LastName = "UpdatedName";
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
        }

        [Fact]
        public void Edit_POST_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                ID = 10,
                LastName = "Anderson",
                FirstMidName = "Alice",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
