using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain queue to ensure clean state
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification!.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("TestUser", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_GeneratesMessageWithId()
        {
            _service.SendNotification("Course", "101", EntityOperation.UPDATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Course (ID: 101)", notification!.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesMessageWithName()
        {
            _service.SendNotification("Student", "1", "Alice Anderson", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Student 'Alice Anderson'", notification!.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_Delete_GeneratesCorrectMessage()
        {
            _service.SendNotification("Department", "5", "Physics", EntityOperation.DELETE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("deleted", notification!.Message);
        }

        [Fact]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification!.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.True(notification!.CreatedAt >= before);
            Assert.True(notification.CreatedAt <= DateTime.Now);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();

            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_FIFOOrder()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first!.EntityType);
            Assert.Equal("B", second!.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));

            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();

            var exception = Record.Exception(() => service.Dispose());

            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_MultipleNotifications_AllReceivable()
        {
            for (int i = 0; i < 5; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }

            Assert.Equal(5, count);
        }
    }
}

using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.Create();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.FirstOrDefault(s => s.LastName == "Test");
            Assert.NotNull(retrieved);
            Assert.Equal("Student", retrieved!.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            var dept = new Department
            {
                Name = "Test Dept",
                Budget = 100000m,
                StartDate = DateTime.Now
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 5001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Find(5001);
            Assert.NotNull(retrieved);
            Assert.Equal("Test Course", retrieved!.Title);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "TestInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.FirstOrDefault(i => i.LastName == "TestInstructor");
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            var department = new Department
            {
                Name = "TestDept",
                Budget = 50000m,
                StartDate = new DateTime(2023, 1, 1)
            };

            _context.Departments.Add(department);
            _context.SaveChanges();

            var retrieved = _context.Departments.FirstOrDefault(d => d.Name == "TestDept");
            Assert.NotNull(retrieved);
            Assert.Equal(50000m, retrieved!.Budget);
        }

        [Fact]
        public void CanAddEnrollment_WithRelationships()
        {
            var student = new Student
            {
                LastName = "EnrollTest",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Now
            };
            _context.Students.Add(student);

            var dept = new Department { Name = "Dept", Budget = 1000, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 6001, Title = "EnrollCourse", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = 6001,
                Grade = Grade.A
            };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.Include(e => e.Student).Include(e => e.Course)
                .FirstOrDefault(e => e.StudentID == student.ID && e.CourseID == 6001);
            Assert.NotNull(retrieved);
            Assert.Equal(Grade.A, retrieved!.Grade);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            var instructor = new Instructor { LastName = "I", FirstMidName = "T", HireDate = DateTime.Now };
            _context.Instructors.Add(instructor);
            var dept = new Department { Name = "D", Budget = 1, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 7001, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var ca = new CourseAssignment { InstructorID = instructor.ID, CourseID = 7001 };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments.Find(7001, instructor.ID);
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void OfficeAssignment_OneToOneWithInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Office",
                FirstMidName = "Test",
                HireDate = DateTime.Now,
                OfficeAssignment = new OfficeAssignment { Location = "Room 200" }
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .FirstOrDefault(i => i.LastName == "Office");
            Assert.NotNull(retrieved);
            Assert.NotNull(retrieved!.OfficeAssignment);
            Assert.Equal("Room 200", retrieved.OfficeAssignment!.Location);
        }

        [Fact]
        public void Students_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Students);
        }

        [Fact]
        public void Courses_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Courses);
        }

        [Fact]
        public void Departments_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Departments);
        }

        [Fact]
        public void Instructors_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Instructors);
        }

        [Fact]
        public void Enrollments_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Enrollments);
        }

        [Fact]
        public void Notifications_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Notifications);
        }
    }
}

using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 10, 1, 3);

            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 10, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Contains(1, list);
            Assert.Contains(2, list);
            Assert.Contains(3, list);
        }

        [Fact]
        public void HasPreviousPage_PageIndex1_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_PageIndex2_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

            Assert.False(list.HasNextPage); // TotalPages = ceil(10/5) = 2, PageIndex = 2
        }

        [Fact]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            Assert.True(list.HasNextPage); // TotalPages = 2, PageIndex = 1
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var list = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(5, list.Count);
            Assert.Equal(6, list[0]);
            Assert.Equal(10, list[4]);
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var list = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(5, list.Count);
            Assert.Equal(1, list[0]);
            Assert.Equal(5, list[4]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var list = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(2, list.Count); // 12 items, page 3 with size 5 = items 11,12
            Assert.Equal(11, list[0]);
            Assert.Equal(12, list[1]);
        }

        [Fact]
        public void Create_SetsTotalPagesCorrectly()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var list = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(3, list.TotalPages); // ceil(12/5) = 3
        }

        [Fact]
        public void TotalPages_ExactDivision()
        {
            var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);

            Assert.Equal(4, list.TotalPages);
        }

        [Fact]
        public void TotalPages_SingleItem()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);

            Assert.Equal(1, list.TotalPages);
        }
    }
}

