            };

            context.Departments.AddRange(department1, department2);

            var course1 = new Course
            {
                CourseID = 1001,
                Title = "Introduction to CS",
                Credits = 3,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            var course2 = new Course
            {
                CourseID = 1002,
                Title = "Calculus I",
                Credits = 4,
                DepartmentID = 2,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
