using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempPath;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempPath = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempPath);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempPath);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempPath);
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempPath))
            {
                try { Directory.Delete(_tempPath, true); } catch { }
            }
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result!.Model);
            Assert.Equal(3, model.Count);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_WithValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result!.Model);
            Assert.Equal("Introduction to CS", course.Title);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_GET_ReturnsViewWithNewCourse()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result!.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_POST_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 2001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
        }

        [Fact]
        public void Create_POST_ValidCourse_AddsToDatabase()
        {
            var course = new Course
            {
                CourseID = 2001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            _controller.Create(course, null!);

            Assert.Equal(4, _context.Courses.Count());
        }

        [Fact]
        public void Create_POST_WithValidImage_SavesFile()
        {
            var course = new Course
            {
                CourseID = 2002,
                Title = "Course With Image",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 1024);

            var result = _controller.Create(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            var savedCourse = _context.Courses.Find(2002);
            Assert.NotNull(savedCourse);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse!.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_POST_WithInvalidExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 2003,
                Title = "Course Bad Ext",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.exe", "application/exe", 1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_WithOversizedFile_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 2004,
                Title = "Course Big File",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 2005, Credits = 3, DepartmentID = 1 };

            var result = _controller.Create(course, null!) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_GET_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_GET_WithValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result!.Model);
            Assert.Equal("Introduction to CS", course.Title);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_GET_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_POST_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.Find(1001)!;
            course.Title = "Updated Title";
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(course, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
        }

        [Fact]
        public void Edit_POST_WithValidImage_UpdatesFile()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Introduction to CS",
                Credits = 3,
                DepartmentID = 1
            };
            _context.Entry(_context.Courses.Find(1001)!).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var mockFile = CreateMockFormFile("updated.png", "image/png", 2048);

            var result = _controller.Edit(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
        }

        [Fact]
        public void Edit_POST_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1001, Credits = 3, DepartmentID = 1 };

            var result = _controller.Edit(course, null!) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete Tests

        [Fact]
        public void Delete_GET_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_GET_WithValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result!.Model);
            Assert.Equal("Introduction to CS", course.Title);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1001) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Equal(2, _context.Courses.Count());
        }

        #endregion

        #region Helpers

        private static Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var mockFile = new Mock<IFormFile>();
            var content = new byte[Math.Min((int)length, 1024)];
            var ms = new MemoryStream(content);
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.ContentType).Returns(contentType);
            mockFile.Setup(f => f.Length).Returns(length);
            mockFile.Setup(f => f.OpenReadStream()).Returns(ms);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => ms.CopyTo(s));
            return mockFile;
        }

        #endregion
    }
}

