using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.Create();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.FirstOrDefault(s => s.LastName == "Test");
            Assert.NotNull(retrieved);
            Assert.Equal("Student", retrieved!.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            var dept = new Department
            {
                Name = "Test Dept",
                Budget = 100000m,
                StartDate = DateTime.Now
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 5001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Find(5001);
            Assert.NotNull(retrieved);
            Assert.Equal("Test Course", retrieved!.Title);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "TestInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1)
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.FirstOrDefault(i => i.LastName == "TestInstructor");
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            var department = new Department
            {
                Name = "TestDept",
                Budget = 50000m,
                StartDate = new DateTime(2023, 1, 1)
            };

            _context.Departments.Add(department);
            _context.SaveChanges();

            var retrieved = _context.Departments.FirstOrDefault(d => d.Name == "TestDept");
            Assert.NotNull(retrieved);
            Assert.Equal(50000m, retrieved!.Budget);
        }

        [Fact]
        public void CanAddEnrollment_WithRelationships()
        {
            var student = new Student
            {
                LastName = "EnrollTest",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Now
            };
            _context.Students.Add(student);

            var dept = new Department { Name = "Dept", Budget = 1000, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 6001, Title = "EnrollCourse", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = 6001,
                Grade = Grade.A
            };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.Include(e => e.Student).Include(e => e.Course)
                .FirstOrDefault(e => e.StudentID == student.ID && e.CourseID == 6001);
            Assert.NotNull(retrieved);
            Assert.Equal(Grade.A, retrieved!.Grade);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            var instructor = new Instructor { LastName = "I", FirstMidName = "T", HireDate = DateTime.Now };
            _context.Instructors.Add(instructor);
            var dept = new Department { Name = "D", Budget = 1, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 7001, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var ca = new CourseAssignment { InstructorID = instructor.ID, CourseID = 7001 };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments.Find(7001, instructor.ID);
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void OfficeAssignment_OneToOneWithInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Office",
                FirstMidName = "Test",
                HireDate = DateTime.Now,
                OfficeAssignment = new OfficeAssignment { Location = "Room 200" }
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .FirstOrDefault(i => i.LastName == "Office");
            Assert.NotNull(retrieved);
            Assert.NotNull(retrieved!.OfficeAssignment);
            Assert.Equal("Room 200", retrieved.OfficeAssignment!.Location);
        }

        [Fact]
        public void Students_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Students);
        }

        [Fact]
        public void Courses_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Courses);
        }

        [Fact]
        public void Departments_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Departments);
        }

        [Fact]
        public void Instructors_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Instructors);
        }

        [Fact]
        public void Enrollments_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Enrollments);
        }

        [Fact]
        public void Notifications_DbSet_IsNotNull()
        {
            Assert.NotNull(_context.Notifications);
        }
    }
}

