using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 10, 1, 3);

            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 10, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Contains(1, list);
            Assert.Contains(2, list);
            Assert.Contains(3, list);
        }

        [Fact]
        public void HasPreviousPage_PageIndex1_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_PageIndex2_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

            Assert.False(list.HasNextPage); // TotalPages = ceil(10/5) = 2, PageIndex = 2
        }

        [Fact]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            Assert.True(list.HasNextPage); // TotalPages = 2, PageIndex = 1
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var list = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(5, list.Count);
            Assert.Equal(6, list[0]);
            Assert.Equal(10, list[4]);
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var list = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(5, list.Count);
            Assert.Equal(1, list[0]);
            Assert.Equal(5, list[4]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var list = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(2, list.Count);
            Assert.Equal(11, list[0]);
            Assert.Equal(12, list[1]);
        }

        [Fact]
        public void Create_SetsTotalPagesCorrectly()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var list = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(3, list.TotalPages); // ceil(12/5) = 3
        }

        [Fact]
        public void TotalPages_ExactDivision()
        {
            var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);

            Assert.Equal(4, list.TotalPages);
        }

        [Fact]
        public void TotalPages_SingleItem()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);

            Assert.Equal(1, list.TotalPages);
        }
    }
}

